const API_BASE = '/api';

export const exportApi = {
  // Export data as CSV with optional client filtering
  exportCsv: (clientId?: string): string => {
    const params = clientId ? `?clientId=${encodeURIComponent(clientId)}` : '';
    return `${API_BASE}/export/csv${params}`;
  },
};
